def countPairs(arr, n):
    # Create a new hashmap named hm to store the count of each unique element
    hm = {}
    for i in range(n):
        # If this is the first time we've seen this element, set its count to 1
        if arr[i] not in hm:
            hm[arr[i]] = 1
        # Otherwise, increment its count by 1
        else:
            hm[arr[i]] += 1
    # Initialize the total count of pairs to 0
    ans = 0
    for key, value in hm.items():
        # If we have at least 2 of this key, we can use them to make a pair
        if value >= 2:
            # Get the count of pairs by multiplying the count of elements by itself, minus one
            # Why minus one? Because, if we have 3 of the same number, we can form 3 pairs (2,1)
            # That means we should only add the first two numbers to our total count
            ans += (value * (value - 1)) / 2
    return ans

